import java.util.Scanner;

public class SafeBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name:");
        String name = scanner.next(); // User input

        char[] buffer = new char[10]; // Buffer with fixed size

        // Copy user input into buffer with proper bounds checking
        for (int i = 0; i < Math.min(name.length(), buffer.length); i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
